19	// These structures are modeled after RTLIL's SwitchRule and CaseRule, to which
20	// they are eventually lowered.
21	//
22	// There are two key distinctions:
23	//
24	//  - we retain slang location and symbol information for the switches and cases
25	//    in question
26	//
27	//  - the LHS of actions represent "HDL intent" rather than actual netlist-level
28	//    signals, these differ because we need to insert flip-flops or latches, and
29	//    because we may need to dynamically mask the individual assignments
30	//
31	struct Case;
32	struct Switch
33	{
34		int level;
35		const ast::Statement *statement = nullptr;
36	
37		RTLIL::SigSpec signal;
38		std::vector<Case *> cases;
39	
40		bool full_case = false;
41		bool parallel_case = false;
42	
43		~Switch();
44		Case *add_case(std::vector<RTLIL::SigSpec> compare);
45		RTLIL::SwitchRule *lower(NetlistContext &netlist);
46	
47		// trivial switch has signal={}, one case, and no special attributes
48		bool trivial();
49	};
50	
51	struct Case
52	{
53		int level = 0;
54		const ast::Statement *statement = nullptr;
55	
56		struct Action
57		{
58			slang::SourceLocation loc;
59	
60			VariableBits lvalue;
61			RTLIL::SigSpec mask;
62			RTLIL::SigSpec unmasked_rvalue;
63		};
64		std::vector<RTLIL::SigSpec> compare;
65		std::vector<Action> actions;
66		std::vector<Switch *> switches;
67		std::vector<RTLIL::SigSig> aux_actions;
68	
69		~Case()
70		{
71			for (auto switch_ : switches)
72				delete switch_;
73		}
74	
75		Switch *add_switch(RTLIL::SigSpec signal)
76		{
77			Switch *sw = new Switch;
78			sw->signal = signal;
79			sw->level = level + 1;
80			switches.push_back(sw);
81			return sw;
82		}
83	
84		void copy_into(NetlistContext &netlist, RTLIL::CaseRule *rule)
85		{
86			if (statement)
87				transfer_attrs(netlist, *statement, rule);
88	
89			rule->compare = compare;
90			rule->actions.insert(rule->actions.end(), aux_actions.begin(), aux_actions.end());
91	
92			std::vector<Switch *>::iterator it, ite;
93			it = switches.begin();
94			ite = switches.end();
95			for (; it != ite; it++) {
96				// opportunistic optimization to reduce tree depth: helps runtime of proc_prune
97				while (it != ite && it + 1 == ite && (*it)->trivial() && !(*it)->cases[0]->statement) {
98					if (!(*it)->cases[0]->aux_actions.empty()) {
99						RTLIL::SwitchRule *sw = new RTLIL::SwitchRule;
100						rule->switches.push_back(sw);
101						sw->signal = {};
102						RTLIL::CaseRule *case2 = new RTLIL::CaseRule;
103						sw->cases.push_back(case2);
104						case2->actions = (*it)->cases[0]->aux_actions;
105					}
106					ite = (*it)->cases[0]->switches.end();
107					it = (*it)->cases[0]->switches.begin();
108				}
109				if (it == ite)
110					break;
111				rule->switches.push_back((*it)->lower(netlist));
112			}
113		}
114	
115		RTLIL::CaseRule *lower(NetlistContext &netlist)
116		{
117			RTLIL::CaseRule *ret = new RTLIL::CaseRule;
118			copy_into(netlist, ret);
119			return ret;
120		}
121	
122		void insert_latch_signaling(
123				DiagnosticIssuer &issuer, Yosys::dict<VariableBit, RTLIL::SigSig> &map)
124		{
125			std::vector<Switch *> prepended_switches;
126			std::set<VariableBit> has_mask_switches;
127	
128			for (auto &action : actions) {
129				VariableBits lvalue;
130				RTLIL::SigSpec enables, lstaging, rvalue;
131	
132				for (uint64_t i = 0; i < action.lvalue.bitwidth(); i++) {
133					VariableBit lbit = action.lvalue[i];
134	
135					if (map.count(lbit)) {
136						auto &mapped = map.at(lbit);
137	
138						if (action.mask[i] == RTLIL::S1 && !has_mask_switches.count(lbit)) {
139							lvalue.append(lbit);
140							lstaging.append(mapped.second);
141							enables.append(mapped.first);
142							rvalue.append(action.unmasked_rvalue[i]);
143						} else {
144							Switch *sw = new Switch;
145							sw->signal = action.mask[i];
146							sw->level = level + 1;
147							sw->statement = statement;
148							prepended_switches.push_back(sw);
149							Case *case_ = sw->add_case({RTLIL::S1});
150							case_->statement = statement;
151							case_->aux_actions.push_back({mapped.second, action.unmasked_rvalue[i]});
152							case_->aux_actions.push_back({mapped.first, RTLIL::S1});
153							has_mask_switches.insert(lbit);
154						}
155					}
156				}
157	
158				if (!lstaging.empty()) {
159					aux_actions.push_back({lstaging, rvalue});
160					aux_actions.push_back({enables, RTLIL::SigSpec(RTLIL::S1, enables.size())});
161				}
162			}
163	
164			for (auto switch_ : switches)
165				for (auto case_ : switch_->cases)
166					case_->insert_latch_signaling(issuer, map);
167	
168			switches.insert(switches.begin(), prepended_switches.begin(), prepended_switches.end());
169		}
170	};
171	
172	}; // namespace slang_frontend
